import { Search, Sparkles } from 'lucide-react';
import { useMemo, useState } from 'react';
import { componentSnippets } from '../data/snippets';
import type { ComponentSnippet } from '../types';

interface ComponentSidebarProps {
  onInject: (snippet: ComponentSnippet) => void;
}

export function ComponentSidebar({ onInject }: ComponentSidebarProps) {
  const [query, setQuery] = useState('');
  const [category, setCategory] = useState('Todos');

  const categories = useMemo(() => ['Todos', ...Array.from(new Set(componentSnippets.map((snippet) => snippet.category)))], []);

  const filtered = componentSnippets.filter((snippet) => {
    const haystack = `${snippet.name} ${snippet.description} ${snippet.category} ${snippet.tags.join(' ')}`.toLowerCase();
    const matchesQuery = haystack.includes(query.toLowerCase());
    const matchesCategory = category === 'Todos' || snippet.category === category;
    return matchesQuery && matchesCategory;
  });

  return (
    <aside className="sidebar panel">
      <div className="brand">
        <div className="brand-icon"><Sparkles size={20} /></div>
        <div>
          <strong>Component Bank</strong>
          <span>{componentSnippets.length} templates iniciais</span>
        </div>
      </div>

      <label className="search-box">
        <Search size={16} />
        <input value={query} onChange={(event) => setQuery(event.target.value)} placeholder="Buscar componente..." />
      </label>

      <div className="chip-list">
        {categories.map((item) => (
          <button className={item === category ? 'chip active' : 'chip'} key={item} onClick={() => setCategory(item)}>
            {item}
          </button>
        ))}
      </div>

      <div className="snippet-list">
        {filtered.map((snippet) => (
          <button className="snippet-card" key={snippet.id} onClick={() => onInject(snippet)}>
            <span>{snippet.category}</span>
            <strong>{snippet.name}</strong>
            <p>{snippet.description}</p>
          </button>
        ))}
      </div>
    </aside>
  );
}
