import JSZip from 'jszip';
import type { CodeState } from '../types';

export interface ImportedProject {
  code: CodeState;
  source: string;
  warnings: string[];
}

const textDecoderExtensions = ['.html', '.htm', '.css', '.js', '.json', '.txt'];

function downloadBlob(filename: string, blob: Blob) {
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = filename;
  anchor.click();
  URL.revokeObjectURL(url);
}

function normalizePath(path: string) {
  return path.replace(/^\.\//, '').toLowerCase();
}

function chooseFile(paths: string[], candidates: string[]) {
  const normalized = paths.map((path) => ({ path, normalized: normalizePath(path) }));

  for (const candidate of candidates) {
    const found = normalized.find((entry) => entry.normalized.endsWith(candidate));
    if (found) return found.path;
  }

  return undefined;
}

function stripHtmlShell(documentText: string): CodeState {
  const parser = new DOMParser();
  const doc = parser.parseFromString(documentText, 'text/html');

  const inlineCss = Array.from(doc.querySelectorAll('style'))
    .map((style) => style.textContent?.trim() ?? '')
    .filter(Boolean)
    .join('\n\n');

  const inlineJs = Array.from(doc.querySelectorAll('script:not([src])'))
    .map((script) => script.textContent?.trim() ?? '')
    .filter(Boolean)
    .join('\n\n');

  doc.querySelectorAll('style, script').forEach((node) => node.remove());

  const html = doc.body?.innerHTML.trim() || documentText.trim();

  return {
    html,
    css: inlineCss,
    js: inlineJs
  };
}

function buildStandaloneHtml(code: CodeState) {
  return `<!doctype html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Projeto exportado</title>
  <link rel="stylesheet" href="styles.css" />
</head>
<body>
${code.html}
  <script src="script.js"></script>
</body>
</html>
`;
}

export async function exportProjectZip(code: CodeState) {
  const zip = new JSZip();
  zip.file('index.html', buildStandaloneHtml(code));
  zip.file('styles.css', code.css);
  zip.file('script.js', code.js);
  zip.file('code-ide-project.json', JSON.stringify({ version: 1, code, exportedAt: new Date().toISOString() }, null, 2));
  zip.file('README.txt', 'Projeto exportado pelo Code IDE Studio.\nAbra index.html no navegador ou importe este ZIP novamente no editor.\n');

  const blob = await zip.generateAsync({ type: 'blob', compression: 'DEFLATE', compressionOptions: { level: 6 } });
  downloadBlob('code-ide-project.zip', blob);
}

export async function importProjectZip(file: File): Promise<ImportedProject> {
  const zip = await JSZip.loadAsync(file);
  const paths = Object.keys(zip.files).filter((path) => !zip.files[path].dir);
  const warnings: string[] = [];

  const readablePaths = paths.filter((path) => textDecoderExtensions.some((extension) => normalizePath(path).endsWith(extension)));

  const projectJsonPath = chooseFile(readablePaths, ['code-ide-project.json']);
  if (projectJsonPath) {
    const raw = await zip.files[projectJsonPath].async('string');
    const parsed = JSON.parse(raw) as { code?: Partial<CodeState> };
    if (parsed.code?.html !== undefined || parsed.code?.css !== undefined || parsed.code?.js !== undefined) {
      return {
        source: projectJsonPath,
        warnings,
        code: {
          html: parsed.code.html ?? '',
          css: parsed.code.css ?? '',
          js: parsed.code.js ?? ''
        }
      };
    }
  }

  const htmlPath = chooseFile(readablePaths, ['index.html', 'index.htm', '.html', '.htm']);
  if (!htmlPath) {
    throw new Error('Nenhum index.html ou arquivo HTML foi encontrado dentro do ZIP.');
  }

  const htmlRaw = await zip.files[htmlPath].async('string');
  const extracted = stripHtmlShell(htmlRaw);

  const cssPath = chooseFile(readablePaths, ['styles.css', 'style.css', 'main.css', 'app.css', '.css']);
  const jsPath = chooseFile(readablePaths, ['script.js', 'main.js', 'app.js', 'index.js', '.js']);

  if (cssPath) {
    const css = await zip.files[cssPath].async('string');
    extracted.css = [extracted.css, css].filter(Boolean).join('\n\n');
  } else {
    warnings.push('Nenhum CSS separado foi encontrado. Mantive apenas CSS inline do HTML.');
  }

  if (jsPath) {
    const js = await zip.files[jsPath].async('string');
    extracted.js = [extracted.js, js].filter(Boolean).join('\n\n');
  } else {
    warnings.push('Nenhum JS separado foi encontrado. Mantive apenas scripts inline do HTML.');
  }

  return { code: extracted, source: htmlPath, warnings };
}
