import Editor, { OnMount, useMonaco } from '@monaco-editor/react';
import { useEffect } from 'react';
import type { EditorTab, ProblemItem } from '../types';
import { extensionForTab, problemToMonacoMarker } from '../utils/validators';

interface EditorPaneProps {
  activeTab: EditorTab;
  value: string;
  problems: ProblemItem[];
  onChange: (value: string) => void;
}

const languageByTab: Record<EditorTab, string> = {
  html: 'html',
  css: 'css',
  js: 'javascript'
};

export function EditorPane({ activeTab, value, problems, onChange }: EditorPaneProps) {
  const monaco = useMonaco();
  const path = `file:///workspace/index.${extensionForTab(activeTab)}`;

  useEffect(() => {
    if (!monaco) return;
    const uri = monaco.Uri.parse(path);
    const model = monaco.editor.getModel(uri);
    if (!model) return;
    monaco.editor.setModelMarkers(
      model,
      'code-ide-studio',
      problems.filter((problem) => problem.source === activeTab).map(problemToMonacoMarker)
    );
  }, [activeTab, monaco, path, problems]);

  const handleMount: OnMount = (editor, monacoInstance) => {
    editor.focus();
    monacoInstance.editor.setTheme('vs-dark');

    const model = editor.getModel();
    if (!model) return;

    monacoInstance.editor.setModelMarkers(
      model,
      'code-ide-studio',
      problems.filter((problem) => problem.source === activeTab).map(problemToMonacoMarker)
    );
  };

  return (
    <Editor
      height="100%"
      path={path}
      language={languageByTab[activeTab]}
      value={value}
      theme="vs-dark"
      onMount={handleMount}
      onChange={(nextValue) => onChange(nextValue ?? '')}
      options={{
        minimap: { enabled: false },
        fontSize: 14,
        fontLigatures: true,
        wordWrap: 'on',
        automaticLayout: true,
        smoothScrolling: true,
        tabSize: 2,
        formatOnPaste: true,
        formatOnType: true,
        scrollBeyondLastLine: false,
        padding: { top: 16, bottom: 16 }
      }}
    />
  );
}
