import { RotateCcw } from 'lucide-react';
import type { CodeState } from '../types';
import { buildPreviewDocument } from '../utils/buildPreview';

interface PreviewPaneProps {
  code: CodeState;
  previewKey: number;
  onRefresh: () => void;
}

export function PreviewPane({ code, previewKey, onRefresh }: PreviewPaneProps) {
  return (
    <section className="panel preview-panel">
      <header className="panel-header">
        <div>
          <span className="panel-kicker">Preview seguro</span>
          <h2>Resultado</h2>
        </div>
        <button className="icon-button" onClick={onRefresh} title="Recarregar preview">
          <RotateCcw size={18} />
        </button>
      </header>
      <iframe
        key={previewKey}
        title="Preview do projeto"
        className="preview-frame"
        sandbox="allow-scripts allow-forms allow-modals"
        srcDoc={buildPreviewDocument(code)}
      />
    </section>
  );
}
