import type { CodeState, EditorTab, ProblemItem } from '../types';

const lineColumnFromIndex = (source: string, index: number) => {
  const lines = source.slice(0, Math.max(0, index)).split('\n');
  return { line: lines.length, column: lines[lines.length - 1].length + 1 };
};

function validateHtml(html: string): ProblemItem[] {
  const problems: ProblemItem[] = [];
  const parser = new DOMParser();
  const document = parser.parseFromString(html, 'text/html');
  const parseError = document.querySelector('parsererror');

  if (parseError) {
    problems.push({ source: 'html', line: 1, column: 1, severity: 'error', message: 'HTML inválido ou mal formado.' });
  }

  const openTags = html.match(/<([a-z][a-z0-9-]*)(\s[^>]*)?>/gi) ?? [];
  const closeTags = html.match(/<\/([a-z][a-z0-9-]*)>/gi) ?? [];
  if (openTags.length > closeTags.length + 8) {
    problems.push({ source: 'html', line: 1, column: 1, severity: 'warning', message: 'Confira se existem tags abertas sem fechamento.' });
  }

  return problems;
}

function validateCss(css: string): ProblemItem[] {
  const problems: ProblemItem[] = [];
  const openBraces = (css.match(/{/g) ?? []).length;
  const closeBraces = (css.match(/}/g) ?? []).length;

  if (openBraces !== closeBraces) {
    const index = css.lastIndexOf(openBraces > closeBraces ? '{' : '}');
    const position = lineColumnFromIndex(css, index);
    problems.push({ source: 'css', ...position, severity: 'error', message: 'Quantidade de chaves { } inconsistente no CSS.' });
  }

  const missingSemicolonRegex = /[^{};\s]\s*\n\s*[a-z-]+\s*:/gi;
  const match = missingSemicolonRegex.exec(css);
  if (match) {
    const position = lineColumnFromIndex(css, match.index);
    problems.push({ source: 'css', ...position, severity: 'warning', message: 'Possível ponto e vírgula ausente antes desta linha.' });
  }

  return problems;
}

function validateJavaScript(js: string): ProblemItem[] {
  const problems: ProblemItem[] = [];

  try {
    // Validação sintática leve. Para produção, troque por ESLint/LSP em Web Worker.
    new Function(js);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Erro de sintaxe em JavaScript.';
    const lineMatch = message.match(/line\s+(\d+)/i);
    problems.push({ source: 'js', line: lineMatch ? Number(lineMatch[1]) : 1, column: 1, severity: 'error', message });
  }

  if (/document\.write\(/.test(js)) {
    problems.push({ source: 'js', line: 1, column: 1, severity: 'warning', message: 'Evite document.write; prefira manipular o DOM com APIs modernas.' });
  }

  return problems;
}

export function validateCode(code: CodeState): ProblemItem[] {
  return [...validateHtml(code.html), ...validateCss(code.css), ...validateJavaScript(code.js)];
}

export function problemToMonacoMarker(problem: ProblemItem) {
  const severityMap = { error: 8, warning: 4, info: 2 } as const;
  return {
    startLineNumber: problem.line,
    startColumn: problem.column,
    endLineNumber: problem.line,
    endColumn: problem.column + 10,
    message: problem.message,
    severity: severityMap[problem.severity]
  };
}

export function extensionForTab(tab: EditorTab): string {
  return tab === 'html' ? 'html' : tab === 'css' ? 'css' : 'js';
}
