import type { ProblemItem } from '../types';

interface ProblemsPanelProps {
  problems: ProblemItem[];
}

export function ProblemsPanel({ problems }: ProblemsPanelProps) {
  return (
    <section className="problems-panel">
      <header>
        <strong>Problemas</strong>
        <span>{problems.length}</span>
      </header>
      {problems.length === 0 ? (
        <p className="empty-state">Nenhum erro encontrado no momento.</p>
      ) : (
        <ul>
          {problems.map((problem, index) => (
            <li key={`${problem.source}-${problem.line}-${index}`} className={`problem ${problem.severity}`}>
              <span>{problem.source.toUpperCase()} · linha {problem.line}</span>
              {problem.message}
            </li>
          ))}
        </ul>
      )}
    </section>
  );
}
