import { Code2, Cuboid, Download, Eye, FileArchive, FileCode2, Play, Upload } from 'lucide-react';
import { ChangeEvent, useEffect, useMemo, useRef, useState } from 'react';
import { BlocklyPane } from './components/BlocklyPane';
import { ComponentSidebar } from './components/ComponentSidebar';
import { EditorPane } from './components/EditorPane';
import { PreviewPane } from './components/PreviewPane';
import { ProblemsPanel } from './components/ProblemsPanel';
import type { CodeState, ComponentSnippet, EditorTab } from './types';
import { defaultCode } from './utils/defaultCode';
import { validateCode } from './utils/validators';
import { exportProjectZip, importProjectZip } from './utils/fileProject';
import './styles/global.css';

const tabs: Array<{ id: EditorTab; label: string }> = [
  { id: 'html', label: 'HTML' },
  { id: 'css', label: 'CSS' },
  { id: 'js', label: 'JS' }
];

function downloadFile(filename: string, content: string, type = 'text/plain') {
  const blob = new Blob([content], { type });
  const url = URL.createObjectURL(blob);
  const anchor = document.createElement('a');
  anchor.href = url;
  anchor.download = filename;
  anchor.click();
  URL.revokeObjectURL(url);
}

export default function App() {
  const [code, setCode] = useState<CodeState>(() => {
    const saved = localStorage.getItem('code-ide-studio');
    return saved ? JSON.parse(saved) as CodeState : defaultCode;
  });
  const [activeTab, setActiveTab] = useState<EditorTab>('html');
  const [mode, setMode] = useState<'code' | 'blocks'>('code');
  const [previewKey, setPreviewKey] = useState(0);
  const [fileStatus, setFileStatus] = useState('Projeto salvo localmente no navegador.');
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  const problems = useMemo(() => validateCode(code), [code]);

  useEffect(() => {
    const id = window.setTimeout(() => {
      localStorage.setItem('code-ide-studio', JSON.stringify(code));
    }, 250);
    return () => window.clearTimeout(id);
  }, [code]);

  function updateCode(tab: EditorTab, value: string) {
    setCode((current) => ({ ...current, [tab]: value }));
  }

  function injectSnippet(snippet: ComponentSnippet) {
    setCode((current) => ({
      html: `${current.html}\n\n${snippet.html}`,
      css: snippet.css ? `${current.css}\n\n/* ${snippet.name} */\n${snippet.css}` : current.css,
      js: snippet.js ? `${current.js}\n\n// ${snippet.name}\n${snippet.js}` : current.js
    }));
    setMode('code');
  }

  function exportSingleHtml() {
    const fullDocument = `<!doctype html>\n<html lang="pt-BR">\n<head>\n  <meta charset="UTF-8" />\n  <meta name="viewport" content="width=device-width, initial-scale=1.0" />\n  <title>Export Code IDE Studio</title>\n  <style>\n${code.css}\n  </style>\n</head>\n<body>\n${code.html}\n  <script>\n${code.js}\n  </script>\n</body>\n</html>`;
    downloadFile('index.html', fullDocument, 'text/html');
    setFileStatus('index.html exportado com HTML, CSS e JS embutidos.');
  }

  async function exportZip() {
    try {
      await exportProjectZip(code);
      setFileStatus('ZIP exportado com index.html, styles.css, script.js e arquivo de reimportação.');
    } catch (error) {
      setFileStatus(error instanceof Error ? error.message : 'Não foi possível exportar o ZIP.');
    }
  }

  async function handleZipUpload(event: ChangeEvent<HTMLInputElement>) {
    const file = event.target.files?.[0];
    event.target.value = '';
    if (!file) return;

    try {
      const imported = await importProjectZip(file);
      setCode(imported.code);
      setActiveTab('html');
      setMode('code');
      setPreviewKey((value) => value + 1);
      const warningText = imported.warnings.length ? ` Avisos: ${imported.warnings.join(' ')}` : '';
      setFileStatus(`ZIP carregado: ${file.name}. Entrada principal: ${imported.source}.${warningText}`);
    } catch (error) {
      setFileStatus(error instanceof Error ? error.message : 'Falha ao carregar o ZIP.');
    }
  }

  function applyGeneratedBlocks(generated: string) {
    setCode((current) => ({ ...current, js: `${current.js}\n\n// Código gerado pelo Blockly\n${generated}` }));
    setActiveTab('js');
    setMode('code');
  }

  return (
    <div className="app">
      <header className="topbar">
        <div className="logo">
          <div><Code2 size={22} /></div>
          <span>Code IDE Studio</span>
        </div>
        <div className="topbar-actions">
          <button className={mode === 'code' ? 'mode-button active' : 'mode-button'} onClick={() => setMode('code')}>
            <FileCode2 size={17} /> Código
          </button>
          <button className={mode === 'blocks' ? 'mode-button active' : 'mode-button'} onClick={() => setMode('blocks')}>
            <Cuboid size={17} /> Blocos
          </button>
          <input ref={fileInputRef} className="hidden-file-input" type="file" accept=".zip,application/zip,application/x-zip-compressed" onChange={handleZipUpload} />
          <button className="mode-button" onClick={() => fileInputRef.current?.click()}>
            <Upload size={17} /> Carregar ZIP
          </button>
          <button className="mode-button" onClick={exportZip}>
            <FileArchive size={17} /> Salvar ZIP
          </button>
          <button className="mode-button" onClick={exportSingleHtml}>
            <Download size={17} /> HTML
          </button>
        </div>
      </header>

      <main className="workspace">
        <ComponentSidebar onInject={injectSnippet} />

        <section className="editor-column panel">
          <header className="editor-toolbar">
            <div className="tab-list">
              {tabs.map((tab) => (
                <button className={activeTab === tab.id ? 'tab active' : 'tab'} key={tab.id} onClick={() => setActiveTab(tab.id)}>
                  {tab.label}
                </button>
              ))}
            </div>
            <button className="run-button" onClick={() => setPreviewKey((value) => value + 1)}>
              <Play size={16} /> Rodar
            </button>
          </header>

          {mode === 'code' ? (
            <EditorPane
              activeTab={activeTab}
              value={code[activeTab]}
              problems={problems}
              onChange={(value) => updateCode(activeTab, value)}
            />
          ) : (
            <BlocklyPane onGenerateJavaScript={applyGeneratedBlocks} />
          )}

          <ProblemsPanel problems={problems} />
        </section>

        <section className="right-column">
          <div className="preview-title">
            <Eye size={18} /> Atualização quase instantânea via iframe sandbox
          </div>
          <div className="file-status">{fileStatus}</div>
          <PreviewPane code={code} previewKey={previewKey} onRefresh={() => setPreviewKey((value) => value + 1)} />
        </section>
      </main>
    </div>
  );
}
