import * as Blockly from 'blockly';
import { javascriptGenerator } from 'blockly/javascript';
import { useEffect, useRef } from 'react';

interface BlocklyPaneProps {
  onGenerateJavaScript: (code: string) => void;
}

const toolbox = {
  kind: 'categoryToolbox',
  contents: [
    {
      kind: 'category',
      name: 'Lógica',
      colour: '#3b82f6',
      contents: [
        { kind: 'block', type: 'controls_if' },
        { kind: 'block', type: 'logic_compare' },
        { kind: 'block', type: 'logic_operation' },
        { kind: 'block', type: 'logic_boolean' }
      ]
    },
    {
      kind: 'category',
      name: 'Loops',
      colour: '#8b5cf6',
      contents: [
        { kind: 'block', type: 'controls_repeat_ext' },
        { kind: 'block', type: 'controls_whileUntil' }
      ]
    },
    {
      kind: 'category',
      name: 'Texto',
      colour: '#06b6d4',
      contents: [
        { kind: 'block', type: 'text' },
        { kind: 'block', type: 'text_print' },
        { kind: 'block', type: 'text_join' }
      ]
    },
    {
      kind: 'category',
      name: 'Matemática',
      colour: '#f59e0b',
      contents: [
        { kind: 'block', type: 'math_number' },
        { kind: 'block', type: 'math_arithmetic' },
        { kind: 'block', type: 'math_round' }
      ]
    }
  ]
};

export function BlocklyPane({ onGenerateJavaScript }: BlocklyPaneProps) {
  const blocklyDivRef = useRef<HTMLDivElement | null>(null);
  const workspaceRef = useRef<Blockly.WorkspaceSvg | null>(null);

  useEffect(() => {
    if (!blocklyDivRef.current || workspaceRef.current) return;

    workspaceRef.current = Blockly.inject(blocklyDivRef.current, {
      toolbox,
      renderer: 'zelos',
      trashcan: true,
      zoom: {
        controls: true,
        wheel: true,
        startScale: 0.9,
        maxScale: 1.4,
        minScale: 0.55,
        scaleSpeed: 1.1
      },
      grid: {
        spacing: 20,
        length: 3,
        colour: '#263244',
        snap: true
      }
    });

    return () => {
      workspaceRef.current?.dispose();
      workspaceRef.current = null;
    };
  }, []);

  function generateCode() {
    if (!workspaceRef.current) return;
    const generated = javascriptGenerator.workspaceToCode(workspaceRef.current);
    onGenerateJavaScript(generated || '// Nenhum bloco conectado ainda.');
  }

  return (
    <section className="panel blockly-panel">
      <header className="panel-header compact">
        <div>
          <span className="panel-kicker">Modo visual</span>
          <h2>Blockly</h2>
        </div>
        <button className="primary-button" onClick={generateCode}>Converter em JS</button>
      </header>
      <div ref={blocklyDivRef} className="blockly-host" />
    </section>
  );
}
