import type { CodeState } from '../types';

export function buildPreviewDocument(code: CodeState): string {
  return `<!doctype html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <style>
    :root { color-scheme: light; }
    * { box-sizing: border-box; }
    body {
      min-height: 100vh;
      margin: 0;
      padding: 32px;
      font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
      background: radial-gradient(circle at top left, #dbeafe, transparent 28rem), #f8fafc;
      color: #0f172a;
    }
    ${code.css}
  </style>
</head>
<body>
  ${code.html}
  <script>
    window.addEventListener('error', (event) => {
      const payload = { type: 'preview-error', message: event.message, line: event.lineno, column: event.colno };
      window.parent.postMessage(payload, '*');
    });
  </script>
  <script type="module">
    ${code.js}
  </script>
</body>
</html>`;
}
